import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('log', () => {
    it('should log a successful notification', () => {
      const entry = historyService.log(
        {
          id: 'notif-0001',
          type: 'order-confirmation',
          channel: 'email',
          recipient: 'alice@example.com',
          subject: 'Order Confirmation',
          body: 'Your order is confirmed',
          priority: 'normal',
          createdAt: new Date('2026-01-01T10:00:00Z'),
          metadata: { userId: 'user-1' },
        },
        {
          success: true,
          notificationId: 'notif-0001',
          channel: 'email',
          deliveredAt: new Date('2026-01-01T10:00:01Z'),
        },
      );

      expect(entry.id).toBe('nlog-0001');
      expect(entry.status).toBe('sent');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.type).toBe('order-confirmation');
      expect(entry.channel).toBe('email');
      expect(entry.userId).toBe('user-1');
    });

    it('should log a failed notification', () => {
      const entry = historyService.log(
        {
          id: 'notif-0002',
          type: 'order-status-update',
          channel: 'email',
          recipient: 'bob@example.com',
          subject: 'Order Update',
          body: 'Status changed',
          priority: 'normal',
          createdAt: new Date('2026-01-01T10:00:00Z'),
        },
        {
          success: false,
          notificationId: 'notif-0002',
          channel: 'email',
          error: 'No adapter registered for channel: email',
          deliveredAt: new Date('2026-01-01T10:00:01Z'),
        },
      );

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('No adapter registered for channel: email');
    });

    it('should log a suppressed notification', () => {
      const entry = historyService.log(
        {
          id: 'suppressed',
          type: 'user-welcome',
          channel: 'email',
          recipient: 'carol@example.com',
          subject: 'Welcome',
          body: 'Hi',
          priority: 'normal',
          createdAt: new Date('2026-01-01T10:00:00Z'),
        },
        {
          success: false,
          notificationId: 'suppressed',
          channel: 'email',
          error: 'Suppressed by user preferences',
          deliveredAt: new Date('2026-01-01T10:00:01Z'),
        },
      );

      expect(entry.status).toBe('suppressed');
    });
  });

  describe('query', () => {
    function seedEntries() {
      const base = {
        subject: 'Test',
        body: 'Test body',
        priority: 'normal' as const,
      };
      historyService.log(
        { ...base, id: 'n1', type: 'order-confirmation', channel: 'email', recipient: 'alice@example.com', createdAt: new Date('2026-01-01T10:00:00Z'), metadata: { userId: 'user-1' } },
        { success: true, notificationId: 'n1', channel: 'email', deliveredAt: new Date('2026-01-01T10:00:00Z') },
      );
      historyService.log(
        { ...base, id: 'n2', type: 'order-status-update', channel: 'email', recipient: 'bob@example.com', createdAt: new Date('2026-01-02T10:00:00Z'), metadata: { userId: 'user-2' } },
        { success: true, notificationId: 'n2', channel: 'email', deliveredAt: new Date('2026-01-02T10:00:00Z') },
      );
      historyService.log(
        { ...base, id: 'n3', type: 'user-welcome', channel: 'webhook', recipient: 'https://hook.example.com', createdAt: new Date('2026-01-03T10:00:00Z'), metadata: { userId: 'user-3' } },
        { success: false, notificationId: 'n3', channel: 'webhook', error: 'Connection refused', deliveredAt: new Date('2026-01-03T10:00:00Z') },
      );
    }

    it('should return all entries when no filters', () => {
      seedEntries();
      const result = historyService.query();
      expect(result.totalItems).toBe(3);
    });

    it('should filter by userId', () => {
      seedEntries();
      const result = historyService.query({ userId: 'user-1' });
      expect(result.totalItems).toBe(1);
      expect(result.items[0]?.recipient).toBe('alice@example.com');
    });

    it('should filter by recipient', () => {
      seedEntries();
      const result = historyService.query({ recipient: 'bob@example.com' });
      expect(result.totalItems).toBe(1);
      expect(result.items[0]?.type).toBe('order-status-update');
    });

    it('should filter by type', () => {
      seedEntries();
      const result = historyService.query({ type: 'user-welcome' });
      expect(result.totalItems).toBe(1);
    });

    it('should filter by channel', () => {
      seedEntries();
      const result = historyService.query({ channel: 'webhook' });
      expect(result.totalItems).toBe(1);
    });

    it('should filter by status', () => {
      seedEntries();
      const result = historyService.query({ status: 'failed' });
      expect(result.totalItems).toBe(1);
      expect(result.items[0]?.error).toBe('Connection refused');
    });

    it('should filter by date range', () => {
      seedEntries();
      const result = historyService.query({
        from: new Date('2026-01-02T00:00:00Z'),
        to: new Date('2026-01-02T23:59:59Z'),
      });
      expect(result.totalItems).toBe(1);
      expect(result.items[0]?.recipient).toBe('bob@example.com');
    });

    it('should sort by timestamp descending', () => {
      seedEntries();
      const result = historyService.query();
      expect(result.items[0]?.notificationId).toBe('n3');
      expect(result.items[2]?.notificationId).toBe('n1');
    });

    it('should paginate results', () => {
      seedEntries();
      const page1 = historyService.query({ page: 1, pageSize: 2 });
      expect(page1.items).toHaveLength(2);
      expect(page1.hasNext).toBe(true);
      expect(page1.totalPages).toBe(2);

      const page2 = historyService.query({ page: 2, pageSize: 2 });
      expect(page2.items).toHaveLength(1);
      expect(page2.hasNext).toBe(false);
    });

    it('should combine multiple filters', () => {
      seedEntries();
      const result = historyService.query({ channel: 'email', status: 'sent' });
      expect(result.totalItems).toBe(2);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      const base = {
        subject: 'Test',
        body: 'Test',
        priority: 'normal' as const,
      };
      historyService.log(
        { ...base, id: 'n1', type: 'order-confirmation', channel: 'email', recipient: 'a@example.com', createdAt: new Date('2026-01-01'), metadata: { userId: 'u1' } },
        { success: true, notificationId: 'n1', channel: 'email', deliveredAt: new Date('2026-01-01') },
      );
      historyService.log(
        { ...base, id: 'n2', type: 'order-confirmation', channel: 'email', recipient: 'b@example.com', createdAt: new Date('2026-01-02'), metadata: { userId: 'u2' } },
        { success: true, notificationId: 'n2', channel: 'email', deliveredAt: new Date('2026-01-02') },
      );
    });

    it('getByUserId returns entries for a user', () => {
      expect(historyService.getByUserId('u1')).toHaveLength(1);
    });

    it('getByType returns entries by type', () => {
      expect(historyService.getByType('order-confirmation')).toHaveLength(2);
    });

    it('getByDateRange returns entries in range', () => {
      const entries = historyService.getByDateRange(
        new Date('2026-01-01T00:00:00Z'),
        new Date('2026-01-01T23:59:59Z'),
      );
      expect(entries).toHaveLength(1);
    });

    it('count returns total entries', () => {
      expect(historyService.count()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications dispatched via EventBus', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const result = historyService.query();
      expect(result.items[0]?.status).toBe('sent');
      expect(result.items[0]?.recipient).toBe('alice@example.com');
      expect(result.items[0]?.type).toBe('order-confirmation');
    });

    it('should log failed notifications when no adapter', async () => {
      const bareService = new NotificationService(eventBus);
      const bareHistory = new NotificationHistoryService(new NotificationLogRepository(new Database()));
      bareService.setHistoryService(bareHistory);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(bareHistory.count()).toBe(1);
      const result = bareHistory.query();
      expect(result.items[0]?.status).toBe('failed');
    });

    it('should log user-welcome notifications', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-5',
          name: 'Dave',
          email: 'dave@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const result = historyService.query({ type: 'user-welcome' });
      expect(result.totalItems).toBe(1);
      expect(result.items[0]?.userId).toBe('user-5');
    });

    it('should track multiple notifications across events', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'A', email: 'a@example.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: { id: 'o1', userId: 'a@example.com', items: [], total: 10, status: 'confirmed', createdAt: new Date(), updatedAt: new Date() },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(historyService.count()).toBe(2);
      const byType = historyService.getByType('user-welcome');
      expect(byType).toHaveLength(1);
    });
  });
});

