+/**
+ * Notification history service — logs and queries sent notifications.
+ *
+ * Integrates with NotificationService via setHistoryService().
+ * Every dispatched notification is logged with delivery status.
+ */
+
+import type { NotificationLogEntry, DeliveryStatus } from '../models/notification-log.js';
+import type { NotificationChannel, NotificationType, NotificationPayload, NotificationResult } from '../models/notification.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type { PaginationResult } from '../utils/pagination.js';
+import { paginate } from '../utils/pagination.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export interface NotificationHistoryQuery {
+  userId?: string;
+  recipient?: string;
+  type?: NotificationType;
+  channel?: NotificationChannel;
+  status?: DeliveryStatus;
+  from?: Date;
+  to?: Date;
+  page?: number;
+  pageSize?: number;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a notification dispatch result.
+   */
+  log(payload: NotificationPayload, result: NotificationResult): NotificationLogEntry {
+    let status: DeliveryStatus;
+    if (result.success) {
+      status = 'sent';
+    } else if (result.error === 'Suppressed by user preferences') {
+      status = 'suppressed';
+    } else {
+      status = 'failed';
+    }
+
+    const entry: NotificationLogEntry = {
+      id: generateLogId(),
+      notificationId: payload.id,
+      recipient: payload.recipient,
+      channel: payload.channel,
+      type: payload.type,
+      subject: payload.subject,
+      status,
+      error: result.error,
+      timestamp: result.deliveredAt,
+      userId: payload.metadata?.['userId'] as string | undefined,
+      metadata: payload.metadata,
+    };
+
+    this.repository.save(entry);
+    this.logger.info(`Logged notification ${payload.id} [${status}]`);
+    return entry;
+  }
+
+  /**
+   * Query notification history with optional filters and pagination.
+   */
+  query(params: NotificationHistoryQuery = {}): PaginationResult<NotificationLogEntry> {
+    const page = params.page ?? 1;
+    const pageSize = params.pageSize ?? 20;
+
+    let entries = this.repository.findAll();
+
+    if (params.userId) {
+      entries = entries.filter((e) => e.userId === params.userId);
+    }
+    if (params.recipient) {
+      entries = entries.filter((e) => e.recipient === params.recipient);
+    }
+    if (params.type) {
+      entries = entries.filter((e) => e.type === params.type);
+    }
+    if (params.channel) {
+      entries = entries.filter((e) => e.channel === params.channel);
+    }
+    if (params.status) {
+      entries = entries.filter((e) => e.status === params.status);
+    }
+    if (params.from) {
+      entries = entries.filter((e) => e.timestamp >= params.from!);
+    }
+    if (params.to) {
+      entries = entries.filter((e) => e.timestamp <= params.to!);
+    }
+
+    // Sort by timestamp descending (most recent first)
+    entries.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());
+
+    return paginate(entries, page, pageSize);
+  }
+
+  /**
+   * Get history for a specific user.
+   */
+  getByUserId(userId: string): NotificationLogEntry[] {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get history by notification type.
+   */
+  getByType(type: NotificationType): NotificationLogEntry[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get history within a date range.
+   */
+  getByDateRange(from: Date, to: Date): NotificationLogEntry[] {
+    return this.repository.findByDateRange(from, to);
+  }
+
+  /**
+   * Get total count of logged notifications.
+   */
+  count(): number {
+    return this.repository.count();
+  }
+}

